INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('parkplatz-b456-graevenwiesbach', 'Parkplatz B456 (Grävenwiesbach)', 'Wanderparkplatz an der B456 südöstlich von Grävenwiesbach (~353 m); freie Sicht nach W/NW. Laut Melder begrenzte Stellplatzzahl.', 'Zu prüfen', 0, 50.37788, 8.4654, 'Jederzeit frei zugänglich', 'Direkt am Standort', 'Gering', 'Mittel', 'https://www.openstreetmap.org/?mlat=50.37788&mlon=8.4654#map=15/50.37788/8.4654', 'Hintertaunus', 20, 35, '⭐⭐⭐⭐⭐ Ausgezeichnet', 4, 'Freier Horizont bis zum Untergang und eigener Parkplatz. Begrenzte Kapazität – ideal für kleine Gruppen, für großen Andrang zu klein.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('roemerturm-gaulskopf', 'Römerturm Gaulskopf', 'Rekonstruierter Limes-Wachturm auf dem Gaulskopf (~401 m); geschlossene Aussichtsplattform mit Rundbogenfenstern. Zufahrt nur zu Fuß/Rad.', 'Vorschlag', 0, 50.33917, 8.64347, 'Nur zu Fuß erreichbar', '> 500m', 'Sehr gering', 'Mittel', 'https://www.openstreetmap.org/?mlat=50.33917&mlon=8.64347#map=15/50.33917/8.64347', 'Wetterau-Rand', 12.6, 35, '⭐⭐ Eingeschränkt', 3, 'Gelände fast frei, aber am Boden bewaldet; geschlossene Fensterplattform und längerer Fußweg machen ihn für mehrere Beobachter unpraktisch.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('anhoehe-bodenrod', 'Anhöhe Bodenrod', 'Hoch gelegener Punkt oberhalb von Bodenrod im Hintertaunus, freie Sicht nach WNW; Parkmöglichkeit vor Ort noch zu klären.', 'Zu prüfen', 0, 50.39924, 8.5488, 'Jederzeit frei zugänglich', 'Unbekannt', 'Sehr gering', 'Gering', 'https://www.openstreetmap.org/?mlat=50.39924&mlon=8.5488#map=15/50.39924/8.5488', 'Hintertaunus', 19.8, 35, '⭐⭐⭐⭐⭐ Ausgezeichnet', 4, 'Topografisch frei bis zum Untergang. Attraktiv, sobald die Parkfrage vor Ort geklärt ist.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('grueninger-warte', 'Grüninger Warte', 'Mittelalterlicher Wartturm auf offener Kuppe (~278 m) bei Pohlheim-Grüningen, nördliche Wetterau. Freier 360°-Rundblick, jederzeit zugänglich; Turm besteigbar.', 'Zu prüfen', 0, 50.51076, 8.71947, 'Jederzeit frei zugänglich', 'Direkt am Standort', 'Mittel', 'Gering', 'https://www.openstreetmap.org/?mlat=50.51076&mlon=8.71947#map=15/50.51076/8.71947', 'Wetterau-Rand', NULL, 45, '⭐⭐⭐ Gut', 4, 'Offene Kuppe mit rundum freiem Horizont – Maximum und mittlere Phasen frei, nur die allertiefste Sichel knapp verdeckt. Attraktiver Aussichtspunkt, aber mit ~45 min die weiteste Anfahrt im Norden.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('megalithgrab-wetterau', 'Megalithgrab (Wetterau)', 'Jungsteinzeitliches Megalithgrab in der offenen Wetterau (~182 m). Weite, flache Feldlage mit freiem Blick nach WNW; frei zugängliches Bodendenkmal.', 'Zu prüfen', 0, 50.47187, 8.80194, 'Jederzeit frei zugänglich', '100 - 500m', 'Sehr gering', 'Gering', 'https://www.openstreetmap.org/?mlat=50.471866&mlon=8.801942#map=15/50.471866/8.801942', 'Wetterau-Rand', 30.2, 40, '⭐⭐⭐ Gut', 4, 'Offene Flachlandlage mit weitem WNW-Blick – Maximum und mittlere Phasen frei, nur die tiefste Sichel (unter ~1°) verdeckt ein ferner Höhenzug. Thematisch reizvoll; Parkmöglichkeit vor Ort noch zu klären.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('wintersteinturm-ober-moerlen', 'Wintersteinturm (Ober-Mörlen)', 'Winterstein am östlichen Taunusrand (~483 m) mit Aussichtsturm; freier Blick nach W–WNW über die Wetterau. Fußweg vom Parkplatz.', 'Vorschlag', 0, 50.33366, 8.66725, 'Nur zu Fuß erreichbar', '> 500m', 'Mittel', 'Mittel', 'https://www.openstreetmap.org/?mlat=50.33366&mlon=8.66725#map=15/50.33366/8.66725', 'Wetterau-Rand', 12.4, 35, '⭐⭐ Eingeschränkt', 3, 'Gelände frei, kein dominierender Nahkamm im Westen. Am Boden teils Fels/Wald; Turm und Fußweg begrenzen den Gruppeneinsatz.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('johannisberg-bad-nauheim', 'Johannisberg (Bad Nauheim)', 'Freistehende Basaltkuppe am Wetterau-Rand, Rundblick, Ausflugsrestaurant.', 'Zu prüfen', 0, 50.36523, 8.72609, 'Jederzeit frei zugänglich', '< 100 m', 'Mittel', 'Keine bekannt', 'https://www.openstreetmap.org/?mlat=50.36523&mlon=8.72609#map=15/50.36523/8.72609', 'Wetterau-Rand', 17.2, 25, '⭐⭐⭐ Gut', 4, 'Geheimtipp mit Infrastruktur, ideal für den Wetterau-Raum. Nur die tiefste Sichel wird knapp gestreift.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('atzelbergturm-kelkheim', 'Atzelbergturm (Kelkheim)', 'Atzelberg bei Kelkheim (~510 m) mit modernem Aussichtsturm; weiter Rundblick vom Turm. Naher Fernmeldeturm je nach Standpunkt prüfen.', 'Vorschlag', 0, 50.17528, 8.38806, 'Nur zu Fuß erreichbar', '> 500m', 'Mittel', 'Mittel', 'https://www.openstreetmap.org/?mlat=50.17528&mlon=8.38806#map=15/50.17528/8.38806', 'Vordertaunus', 17.3, 40, '⭐⭐ Eingeschränkt', 3, 'Gelände fast frei, gut erreichbar, aber am Boden bewaldet und Plattform klein; naher Fernmeldeturm möglich im Weg.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('kleiner-feldberg', 'Kleiner Feldberg', 'Zweithöchster Taunusgipfel mit Forschungsobservatorium, überwiegend bewaldet.', 'Vorschlag', 0, 50.222, 8.44606, 'Jederzeit frei zugänglich', '100 - 500m', 'Gering', 'Gering', 'https://www.openstreetmap.org/?mlat=50.222&mlon=8.44606#map=15/50.222/8.44606', 'Vordertaunus', 12.2, 25, '⭐⭐ Eingeschränkt', 3, 'Hoch genug, aber am Boden kaum freie WNW-Sicht. Nur mit bekannter Lichtung sinnvoll.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('wolfskueppel-riedelbach', 'Wolfsküppel (Riedelbach)', 'Vollständig bewaldeter Gipfel (545 m) im Östlichen Hintertaunus bei Riedelbach (Weilrod), zwischen Neuweilnau, Altweilnau und Finsternthal. Erreichbar nur über Waldwege; kein Aussichtsturm.', 'Eingeschränkt geeignet', 0, 50.30481, 8.41259, 'Nur zu Fuß erreichbar', '> 500m', 'Sehr gering', 'Mittel', 'https://www.openstreetmap.org/?mlat=50.30481&mlon=8.41259#map=15/50.30481/8.41259', 'Hintertaunus', 17, 40, '⭐⭐ Eingeschränkt', 2, 'Gelände nach WNW frei, aber der Gipfel ist vollständig bewaldet und ohne Aussichtspunkt – praktisch keine freie Sicht. Abgelegen; für die SoFi nur mit gesicherter Lichtung denkbar.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('golfclub-attighof', 'Golfclub Attighof', 'Offenes, ebenes Golfgelände (~363 m) mit freiem WNW-Horizont. Privatgelände – Zugang nur mit Genehmigung; bei Betrieb ggf. viel Publikum.', 'Zu prüfen', 0, 50.44291, 8.51745, 'Privatgelände', '< 100 m', 'Hoch', 'Mittel', 'https://www.openstreetmap.org/?mlat=50.44291&mlon=8.51745#map=15/50.44291/8.51745', 'Hintertaunus', 25.1, 35, '⭐⭐⭐⭐⭐ Ausgezeichnet', 4, 'Topografisch frei bis zum Untergang und ideal ebene Fläche, aber Privatgelände mit möglichem Publikumsandrang – Nutzung nur nach Absprache mit dem Club.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('schwickershausen-korridor', 'Schwickershausen (Korridor)', 'Erkundungskorridor auf offenen Höhen nordöstlich von Schwickershausen (~360 m) mit freiem Blick nach WNW Richtung Goldener Grund. Kein fixer Punkt – private Fläche und Eigentümer-Zustimmung nötig.', 'Zu prüfen', 0, 50.3225, 8.30573, 'Genehmigung erforderlich', 'Unbekannt', 'Sehr gering', 'Mittel', 'https://www.openstreetmap.org/?mlat=50.3225&mlon=8.30573#map=15/50.3225/8.30573', 'Hintertaunus', 24.6, 45, '⭐⭐⭐⭐ Sehr gut', 4, 'Bester Kandidat für eine ruhige, private AGO-Fläche: viel Platz, freier Horizont. Konkrete Fläche, Zufahrt und Horizont aber zwingend vor Ort zu klären.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('pfaffenwiesbach-aussichtspunkt', 'Pfaffenwiesbach (Aussichtspunkt)', 'Höhe bei Pfaffenwiesbach; Parken am Wanderparkplatz, wenige Gehminuten zum Aussichtspunkt mit weiter WNW-Sicht. NICHT der bekannte AGO-Beobachtungsplatz.', 'Zu prüfen', 0, 50.32787, 8.63071, 'Jederzeit frei zugänglich', '100 - 500m', 'Gering', 'Gering', 'https://www.openstreetmap.org/?mlat=50.32787&mlon=8.63071#map=15/50.32787/8.63071', 'Hintertaunus', 11.3, 20, '⭐⭐⭐⭐ Sehr gut', 4, 'Sehr freier Horizont, kurzer Fußweg, eigener Parkplatz – guter Mitglieder-Tipp. Nur die allertiefste Sichel geht verloren.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('melibokus-bergstrasse', 'Melibokus (Bergstraße)', 'Höchster Nordgipfel des Odenwalds über der Bergstraße, freier Blick über die Rheinebene (Aussichtsturm vorhanden).', 'Vorschlag', 0, 49.72457, 8.63748, 'Jederzeit frei zugänglich', '100 - 500m', 'Mittel', 'Gering', 'https://www.openstreetmap.org/?mlat=49.72457&mlon=8.63748#map=15/49.72457/8.63748', 'Odenwald/Bergstraße', 55.9, 60, '⭐⭐⭐⭐⭐ Ausgezeichnet', 3, 'Topografisch exzellent, aber ~1 h Fahrt. Lohnt v. a. für Fotografen mit Rheinebene im Vordergrund.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('herzbergturm-bad-homburg', 'Herzbergturm (Bad Homburg)', 'Aussichtsturm am Stadtrand von Bad Homburg (~597 m), Ausflugslokal, kürzeste Anfahrt. Turm überragt den Wald; am Boden liegt der WNW-Horizont hoch.', 'Vorschlag', 0, 50.25558, 8.54333, 'Nur zu Fuß erreichbar', '> 500m', 'Hoch', 'Gering', 'https://www.openstreetmap.org/?mlat=50.25558&mlon=8.54333#map=15/50.25558/8.54333', 'Vordertaunus', 6.2, 15, '⭐ Ungeeignet', 3, 'Stadtnah und bequem, aber am Boden ohne Turm blockiert ein WNW-Horizont von gut 2° die tiefe Endphase – nur frühe und mittlere Phase sicher, dazu Wald.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('glaskopf-schmitten', 'Glaskopf (Schmitten)', 'Bewaldete Kuppe bei Schmitten / Oberreifenberg.', 'Eingeschränkt geeignet', 0, 50.259, 8.40578, 'Nur zu Fuß erreichbar', '100 - 500m', 'Sehr gering', 'Mittel', 'https://www.openstreetmap.org/?mlat=50.259&mlon=8.40578#map=15/50.259/8.40578', 'Hintertaunus', 15.5, 30, '⭐⭐ Eingeschränkt', 3, 'Rechnerisch frei, praktisch durch Wald verdeckt – nur mit gesicherter Lichtung brauchbar.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('pferdskopfturm-treisberg', 'Pferdskopfturm (Treisberg)', 'Bewaldeter Pferdskopf bei Treisberg (~674 m) mit Aussichtsturm; freier Rundblick nur von der Turmplattform.', 'Vorschlag', 0, 50.28971, 8.43335, 'Nur zu Fuß erreichbar', '> 500m', 'Gering', 'Mittel', 'https://www.openstreetmap.org/?mlat=50.28971&mlon=8.43335#map=15/50.28971/8.43335', 'Hintertaunus', 14.9, 30, '⭐⭐ Eingeschränkt', 3, 'Gelände topografisch frei, aber am Boden bewaldet – freie Sicht nur vom Turm (für die Gruppe ungeeignet). Als Boden-Standort kaum nutzbar.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('parkplatz-jammerhecke', 'Parkplatz Jammerhecke', 'Ausgewiesener Wanderparkplatz (Gemarkung Brombach) im Taunus mit recht freiem Blick nach WNW.', 'Zu prüfen', 0, 50.29543, 8.4782, 'Jederzeit frei zugänglich', 'Direkt am Standort', 'Gering', 'Mittel', 'https://www.openstreetmap.org/?mlat=50.29543&mlon=8.4782#map=15/50.29543/8.4782', 'Hintertaunus', 12.5, 30, '⭐⭐⭐ Gut', 4, 'Ruhige Alternative mit eigenem Wanderparkplatz und recht freiem Horizont. Nur die tiefste Sichel wird knapp verdeckt.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('hausbergturm-butzbach', 'Hausbergturm (Butzbach)', 'Hausberg bei Butzbach (~481 m) mit Aussichtsturm; freier Fernblick nach NW vom Turm. Parkplatz ~1,5 km entfernt, Ausrüstung muss getragen werden.', 'Vorschlag', 0, 50.41148, 8.61539, 'Nur zu Fuß erreichbar', '> 500m', 'Gering', 'Mittel', 'https://www.openstreetmap.org/?mlat=50.41148&mlon=8.61539#map=15/50.41148/8.61539', 'Wetterau-Rand', 20.5, 40, '⭐⭐ Eingeschränkt', 3, 'Gelände frei bis zum Untergang, aber am Boden bewaldet, langer Transportweg und enger Turm – eher Backup für ein kleines Team.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('sandplacken', 'Sandplacken', 'Offene Passhöhe zwischen Feldberg und Bad Homburg, Wanderparkplatz, freier Blick nach Westen.', 'Zu prüfen', 0, 50.24567, 8.48637, 'Jederzeit frei zugänglich', '< 100 m', 'Mittel', 'Gering', 'https://www.openstreetmap.org/?mlat=50.24567&mlon=8.48637#map=15/50.24567/8.48637', 'Vordertaunus', 9.6, 20, '⭐⭐⭐⭐⭐ Ausgezeichnet', 5, 'Beste Balance aus freiem Horizont und kurzer Anfahrt; deutlich ruhiger als der Feldberg.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('segelfluggelaende-riedelbach', 'Segelfluggelände Riedelbach', 'Segelfluggelände bei Riedelbach (~513 m), 1000-m-Grasbahn, viel ebene Fläche – organisatorisch ideal, aber nur mit Zustimmung des Sportfliegerclubs (Nutzung begründet kein Recht).', 'Vorschlag', 0, 50.3023, 8.3838, 'Genehmigung erforderlich', '< 100 m', 'Gering', 'Gering', 'https://www.openstreetmap.org/?mlat=50.3023&mlon=8.3838#map=15/50.3023/8.3838', 'Hintertaunus', 18.6, 40, '⭐ Ungeeignet', 3, 'Organisatorisch stark (viel ebene Fläche), aber WNW-Horizont ~2°: Maximum sichtbar, die tiefe Endphase nach ~20:30 geht hinter Gelände/Wald verloren. Nur mit Vereinszustimmung.');
INSERT INTO standorte (slug, standortname, kurzbeschreibung, status, veroeffentlicht, breitengrad, laengengrad, zugaenglichkeit, parkplatz, andrang_erwartet, sicherheitsrisiken, kartenlink, region, entfernung_bad_homburg_km, fahrzeit_minuten, horizontbewertung, gesamtbewertung, kurze_bewertung) VALUES ('grosser-feldberg', 'Großer Feldberg', 'Höchster Gipfel des Taunus. Offenes Plateau (kein Turm nötig), Gastronomie und großer Parkplatz.', 'Geeignet', 1, 50.23408, 8.457478, 'Jederzeit frei zugänglich', '< 100 m', 'Sehr hoch', 'Gering', 'https://www.openstreetmap.org/?mlat=50.23408&mlon=8.457478#map=15/50.23408/8.457478', 'Vordertaunus', 11.4, 25, '⭐⭐⭐⭐⭐ Ausgezeichnet', 5, 'Topografisch perfekt und beste Infrastruktur – die sichere Bank. Wird aber sehr voll, exponiert und kühl.');
